CREATE FUNCTION public.app_current_tenant_id() RETURNS uuid
    LANGUAGE plpgsql STABLE
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  raw text;
BEGIN
  BEGIN
    raw := current_setting('app.tenant_id', true);
  EXCEPTION
    WHEN OTHERS THEN
      RETURN NULL;
  END;

  IF raw IS NULL THEN
    RETURN NULL;
  END IF;

  raw := btrim(raw);
  IF raw = '' THEN
    RETURN NULL;
  END IF;

  BEGIN
    RETURN raw::uuid;
  EXCEPTION
    WHEN invalid_text_representation THEN
      RETURN NULL;
  END;
END;
$$;


